// Basic gameplay struct
USTRUCT(BlueprintType)
struct FWeaponStats {
    GENERATED_BODY()

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    FText Name;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    float Damage = 25.f;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    float FireRate = 0.5f;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    int32 MaxAmmo = 30;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    TSubclassOf<AProjectile> ProjectileClass;
};

// DataTable row struct
USTRUCT(BlueprintType)
struct FItemRow : public FTableRowBase {
    GENERATED_BODY()

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    FText DisplayName;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    TSoftObjectPtr<UTexture2D> Icon;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    int32 StackLimit = 99;
};

// Using a struct
UPROPERTY(EditAnywhere)
FWeaponStats CurrentWeapon;

void Fire() {
    float Dmg = CurrentWeapon.Damage;
}

// Enum declaration
UENUM(BlueprintType)
enum class ECharacterState : uint8 {
    Idle        UMETA(DisplayName = "Idle"),
    Running     UMETA(DisplayName = "Running"),
    Attacking   UMETA(DisplayName = "Attacking"),
    Dodging     UMETA(DisplayName = "Dodging"),
    Dead        UMETA(DisplayName = "Dead"),
};

UENUM(BlueprintType)
enum class EWeaponType : uint8 {
    Melee       UMETA(DisplayName = "Melee"),
    Ranged      UMETA(DisplayName = "Ranged"),
    Magic       UMETA(DisplayName = "Magic"),
    Explosive   UMETA(DisplayName = "Explosive"),
};

// Using in a class
UPROPERTY(EditAnywhere, BlueprintReadWrite)
ECharacterState CurrentState = ECharacterState::Idle;

UPROPERTY(EditAnywhere, BlueprintReadWrite)
EWeaponType WeaponType;

// Switch
void AMyCharacter::UpdateBehavior() {
    switch (CurrentState) {
        case ECharacterState::Idle: PlayIdleAnim(); break;
        case ECharacterState::Running: PlayRunAnim(); break;
        case ECharacterState::Attacking: PlayAttackAnim(); break;
        case ECharacterState::Dead: Ragdoll(); break;
    }
}

// Logging enum value
UE_LOG(LogTemp, Log, TEXT("State: %s"), *UEnum::GetValueAsString(CurrentState));
